CustomField.formula:
( /* ===== Required (75% total) ===== */ IF(NOT(ISBLANK(Name)), 11, 0) + IF(NOT(ISBLANK(TEXT(Type_of_Client__c))), 11, 0) + IF(NOT(ISBLANK(Certificate_of_Incorporation_Business_No__c)), 11, 0) + IF(NOT(ISBLANK(Ardhisasa_Number__c)), 11, 0) + IF(NOT(ISBLANK(KRA_PIN_Number__c)), 11, 0) + IF(NOT(ISBLANK(TEXT(Location_of_Client__c))), 11, 0) + IF(NOT(ISBLANK(Phone)), 9, 0) +
/* ===== Important (22% total, 11 each) ===== */ IF(NOT(ISBLANK(Contact_Person__c)), 11, 0) + IF(NOT(ISBLANK(Physical_Address__c)), 11, 0) +
/* ===== Nice-to-Have (3% total, 1 each) ===== */ IF(NOT(ISBLANK(Other_Email__c)), 1, 0) + IF(NOT(ISBLANK(Postal_Address__c)), 1, 0) + IF(NOT(ISBLANK(Client_Number__c)), 1, 0) )/100
